body.script:
(() => {
  const ns = "http://www.w3.org/1999/xhtml";
  const body = document.querySelector("body");
  if (!body) return;

  const head = document.createElementNS(ns, "head");
  body.prepend(head);

  try { Object.defineProperty(document, "head", { configurable: true, get() { return head; } }); } catch {}
  try { Object.defineProperty(document, "body", { configurable: true, get() { return body; } }); } catch {}
  try { Object.defineProperty(document, "documentElement", { configurable: true, get() { return body; } }); } catch {}

  const originalCreateElement = document.createElement.bind(document);
  document.createElement = function createElement(tagName, options) {
    return typeof tagName === "string"
      ? document.createElementNS(ns, tagName, options)
      : originalCreateElement(tagName, options);
  };

  function copyAttributes(from, to) {
    for (const attr of Array.from(from.attributes || [])) {
      to.setAttribute(attr.name, attr.value);
    }
  }

  function appendExecutableScript(sourceScript, targetParent) {
    const script = document.createElement("script");
    copyAttributes(sourceScript, script);
    if (sourceScript.src) {
      script.src = sourceScript.getAttribute("src");
    } else {
      script.textContent = sourceScript.textContent || "";
    }
    targetParent.appendChild(script);
  }

  function appendNode(sourceNode, targetParent) {
    if (sourceNode.nodeType === Node.TEXT_NODE) {
      targetParent.appendChild(document.createTextNode(sourceNode.textContent || ""));
      return;
    }
    if (sourceNode.nodeType !== Node.ELEMENT_NODE) return;
    if (sourceNode.tagName.toLowerCase() === "script") {
      appendExecutableScript(sourceNode, targetParent);
      return;
    }
    const node = document.createElement(sourceNode.tagName.toLowerCase());
    copyAttributes(sourceNode, node);
    for (const child of Array.from(sourceNode.childNodes)) appendNode(child, node);
    targetParent.appendChild(node);
  }

  async function bootSheepMath() {
    try {
      const response = await fetch("index.html", { cache: "no-store" });
      if (!response.ok) throw new Error("HTTP " + response.status);
      const html = await response.text();
      const parsed = new DOMParser().parseFromString(html, "text/html");

      document.head.innerHTML = "";
      document.body.innerHTML = "";

      for (const node of Array.from(parsed.head.childNodes)) appendNode(node, document.head);
      for (const node of Array.from(parsed.body.childNodes)) appendNode(node, document.body);
    } catch (error) {
      document.body.innerHTML = '<div style="min-height:100vh;display:grid;place-items:center;padding:24px;text-align:center;font:800 20px Arial,sans-serif;background:#132a86;color:white;">SheepMath could not load. Make sure index.html is in the same GitHub folder as this SVG.</div>';
    }
  }

  bootSheepMath();
})();
